let lang=localStorage.getItem('hi-lang')||'ar';
let theme=localStorage.getItem('hi-theme')||'teal';
const themes=['teal','night','garden'];
const themeNames={teal:'🌿 Teal',night:'🌙 Night',garden:'🌿 Garden'};
const themeIcons=['🌿','🌙','🍃'];
let currentConceptIdx=-1;

document.addEventListener('DOMContentLoaded',()=>{setTheme(theme);setLang(lang);initSplash();initTabs();initScrollTop();initTicker();renderHome();renderConcepts();renderComparison();renderHabits();renderQuiz();renderAbout();renderHelp();renderDuas();initScrollReveal();initKeyboardNav();});

function initSplash(){let c=5;const el=document.getElementById('splashCount');const fe=document.getElementById('splashFeatures');if(fe)fe.innerHTML=T[lang].splashFeatures.map((f,i)=>`<div class="splash-feature" style="animation-delay:${0.3+i*0.3}s">${f}</div>`).join('');const iv=setInterval(()=>{c--;if(el)el.textContent=c;if(c<=0){dismissSplash();clearInterval(iv);}},1000);}
function dismissSplash(){const s=document.getElementById('splash');if(s){s.classList.add('hidden');setTimeout(()=>s.style.display='none',500);}playSound('click');}

function setLang(l){lang=l;localStorage.setItem('hi-lang',l);const isRTL=l==='ar';document.documentElement.lang=l;document.documentElement.dir=isRTL?'rtl':'ltr';document.body.dir=isRTL?'rtl':'ltr';document.querySelectorAll('.lang-opt').forEach(b=>b.classList.toggle('active',b.dataset.lang===l));const t=T[l];const set=(id,val)=>{const el=document.getElementById(id);if(el)el.textContent=val;};set('appTitle',t.appTitle);set('splashSub',t.splashSub);set('splashHint',t.splashHint);set('tabHome',t.tabHome);set('tabConcepts',t.tabConcepts);set('tabComparison',t.tabComparison);set('tabHabits',t.tabHabits);set('tabQuiz',t.tabQuiz);set('tabAbout',t.tabAbout);set('conceptsTitle',t.conceptsTitle);set('conceptsDesc',t.conceptsDesc);set('comparisonTitle',t.comparisonTitle);set('comparisonDesc',t.comparisonDesc);set('habitsTitle',t.habitsTitle);set('habitsDesc',t.habitsDesc);set('quizTitle',t.quizTitle);set('quizDesc',t.quizDesc);set('helpTitle',t.helpTitle);set('duaPanelTitle',t.duaPanelTitle);set('habitsReset',t.resetBtn);renderHome();renderConcepts();renderComparison();renderHabits();renderQuiz();renderAbout();renderHelp();renderDuas();const fe=document.getElementById('splashFeatures');if(fe)fe.innerHTML=T[l].splashFeatures.map((f,i)=>`<div class="splash-feature" style="animation-delay:${0.3+i*0.3}s">${f}</div>`).join('');}

function setTheme(t){theme=t;document.documentElement.dataset.theme=t;localStorage.setItem('hi-theme',t);const idx=themes.indexOf(t);const el=document.getElementById('themeIcon');if(el)el.textContent=themeIcons[idx];}
function cycleTheme(){const idx=(themes.indexOf(theme)+1)%themes.length;setTheme(themes[idx]);showToast(themeNames[themes[idx]]);playSound('theme');}
function initTabs(){document.querySelectorAll('.tab').forEach(tab=>{tab.addEventListener('click',()=>{document.querySelectorAll('.tab').forEach(t=>t.classList.remove('active'));document.querySelectorAll('.panel').forEach(p=>p.classList.remove('active'));tab.classList.add('active');const panel=document.getElementById('panel-'+tab.dataset.tab);if(panel)panel.classList.add('active');window.scrollTo({top:0,behavior:'smooth'});playSound('click');});});}
function initTicker(){const el=document.getElementById('tickerText');if(!el)return;const msgs={ar:['⚖️ حقوق الإنسان بين تعاليم الإسلام وإعلان الأمم المتحدة','📖 ٢٠ حقاً أساسياً في الإسلام','🌍 مقارنة شاملة'],en:['⚖️ Human Rights: Islam vs UN Declaration','📖 20 fundamental rights in Islam','🌍 Comprehensive comparison'],fr:['⚖️ Droits de l\'Homme : Islam vs Declaration de l\'ONU','📖 20 droits fondamentaux en Islam','🌍 Comparaison complete']};const items=(msgs[lang]||msgs.en).map(m=>`<span class="tc">&nbsp;&nbsp;&nbsp;${m}&nbsp;&nbsp;&nbsp;</span>`).join('');el.innerHTML=items+items;el.style.animation=`tickerMarquee ${(msgs[lang]||msgs.en).length*12}s linear infinite`;}

function renderHome(){const t=T[lang];const dayIdx=new Date().getDate()%CONCEPTS.length;const c=CONCEPTS[dayIdx][lang];document.getElementById('dailyCard').innerHTML=`<div class="daily-label">${t.dailyLabel}</div><div class="daily-title">${c.title}</div><div class="daily-body">${c.desc}</div><div class="daily-action" onclick="document.querySelector('[data-tab=concepts]').click()">${t.tabConcepts} &#8594;</div>`;const sections=[{icon:'⚖️',tab:'concepts',title:t.tabConcepts,desc:lang==='ar'?'٢٠ حقاً إسلامياً':lang==='fr'?'20 droits islamiques':'20 Islamic rights'},{icon:'🔄',tab:'comparison',title:t.tabComparison,desc:lang==='ar'?'الإسلام والأمم المتحدة':lang==='fr'?'Islam et l\'ONU':'Islam and the UN'},{icon:'📋',tab:'habits',title:t.tabHabits,desc:lang==='ar'?'عادات يومية':lang==='fr'?'Habitudes quotidiennes':'Daily habits'},{icon:'🤔',tab:'quiz',title:t.tabQuiz,desc:lang==='ar'?'اختبر نفسك':lang==='fr'?'Testez-vous':'Test yourself'},{icon:'📖',tab:'about',title:t.tabAbout,desc:lang==='ar'?'عن الكتاب':lang==='fr'?'Le livre':'The book'}];document.getElementById('homeGrid').innerHTML=sections.map(s=>`<div class="home-card" onclick="document.querySelector('[data-tab=${s.tab}]').click()"><span class="hc-icon">${s.icon}</span><div class="hc-title">${s.title}</div><div class="hc-desc">${s.desc}</div></div>`).join('');}

function renderConcepts(){const t=T[lang];const searchBar=`<div class="search-bar"><input type="text" id="conceptsSearch" class="search-input" placeholder="${t.searchPlaceholder}" oninput="filterConcepts(this.value)"><span class="search-icon">🔍</span></div>`;const cards=CONCEPTS.map((c,i)=>{const d=c[lang];return`<div class="principle-card scroll-reveal" id="concept-${c.id}" data-search="${d.title.toLowerCase()}"><div class="principle-head" onclick="toggleCard('concept-${c.id}')"><span class="principle-num">${c.id}</span><span class="principle-emoji">${c.emoji}</span><span class="principle-title">${d.title}</span><span class="principle-chev">&#9660;</span></div><div class="principle-body"><div class="principle-inner"><p class="principle-desc">${d.desc}</p><div class="comparison-box"><div class="comparison-side carnegie-side"><div class="comp-label">${t.islamLabel}</div><div class="comp-text">${d.islam}</div></div><div class="comparison-side ghazali-side"><div class="comp-label">${t.unLabel}</div><div class="comp-text">${d.un}</div></div></div><div class="action-box"><span class="action-icon">💡</span><span>${d.action}</span></div><button class="share-btn" onclick="event.stopPropagation();shareConcept(${i})"><span class="share-icon">&#128279;</span> ${t.share}</button></div></div></div>`;}).join('');document.getElementById('conceptsContainer').innerHTML=searchBar+cards;}
function filterConcepts(q){q=q.toLowerCase().trim();document.querySelectorAll('.principle-card').forEach(card=>{const s=card.dataset.search||'';const t=card.querySelector('.principle-title');card.style.display=(!q||s.includes(q)||(t&&t.textContent.toLowerCase().includes(q)))?'':'none';});}
async function shareConcept(idx){const c=CONCEPTS[idx],d=c[lang];const text=`${c.emoji} ${d.title}\n\n${d.desc}\n\n💡 ${d.action}\n\n— حقوق الإنسان`;if(navigator.share){try{await navigator.share({title:d.title,text});}catch(e){}}else{try{await navigator.clipboard.writeText(text);showToast(lang==='ar'?'تم النسخ!':'Copied!');}catch(e){showToast('Could not copy');}}}

function renderComparison(){document.getElementById('comparisonContainer').innerHTML=COMPARISONS.map(c=>{const d=c[lang];return`<div class="anxiety-card scroll-reveal"><div class="anxiety-header"><span class="anxiety-emoji">${c.emoji}</span><span class="anxiety-title">${d.topic}</span></div><div class="anxiety-problem" style="border-color:var(--primary)"><span class="anxiety-label" style="color:var(--primary)">☪️ ${lang==='ar'?'الإسلام':lang==='fr'?'Islam':'Islam'}</span>${d.islam}</div><div class="anxiety-solution"><span class="anxiety-label" style="color:var(--accent)">🌐 ${lang==='ar'?'الإعلان العالمي':lang==='fr'?'Declaration de l\'ONU':'UN Declaration'}</span>${d.un}</div></div>`;}).join('');}

function renderHabits(){const today=new Date().toDateString();let hs=JSON.parse(localStorage.getItem('hi-habits')||'{}');if(hs.date!==today){updateStreak(hs);hs={date:today,done:[]};localStorage.setItem('hi-habits',JSON.stringify(hs));}const streak=getStreak();const sH=streak>0?`<div class="streak-badge">🔥 ${streak} ${T[lang].streakMsg}</div>`:'';document.getElementById('habitsContainer').innerHTML=HABITS.map((h,i)=>{const d=h[lang];const done=hs.done.includes(i);return`<div class="habit-item ${done?'done':''}" onclick="toggleHabit(${i})"><span class="habit-check">${done?'&#10003;':''}</span><span class="habit-emoji">${h.emoji}</span><div><div class="habit-label">${d.label}</div><div class="habit-source">${d.source}</div></div></div>`;}).join('');const se=document.getElementById('streakBadge');if(se)se.innerHTML=sH;updateHabitsProgress(hs);}
function toggleHabit(i){const today=new Date().toDateString();let hs=JSON.parse(localStorage.getItem('hi-habits')||'{}');if(hs.date!==today)hs={date:today,done:[]};const idx=hs.done.indexOf(i);if(idx>-1)hs.done.splice(idx,1);else hs.done.push(i);localStorage.setItem('hi-habits',JSON.stringify(hs));renderHabits();playSound(idx>-1?'click':'success');if(hs.done.length===HABITS.length){launchConfetti();showToast(T[lang].allDone);}}
function resetHabits(){localStorage.setItem('hi-habits',JSON.stringify({date:new Date().toDateString(),done:[]}));renderHabits();showToast(lang==='ar'?'تم إعادة التعيين':'Reset');}
function updateHabitsProgress(hs){const d=hs.done.length,t=HABITS.length,p=t>0?(d/t*100):0;const f=document.getElementById('habitsFill'),tx=document.getElementById('habitsText');if(f)f.style.width=p+'%';if(tx)tx.textContent=`${d}/${t}`;}
function updateStreak(ps){let sd=JSON.parse(localStorage.getItem('hi-streak')||'{"count":0,"lastDate":""}');if(ps&&ps.done&&ps.done.length===HABITS.length&&ps.date){const y=new Date();y.setDate(y.getDate()-1);if(ps.date===y.toDateString())sd.count++;else if(ps.date!==new Date().toDateString())sd.count=ps.done.length===HABITS.length?1:0;sd.lastDate=ps.date;}else if(ps&&ps.date){sd.count=0;sd.lastDate=ps.date;}localStorage.setItem('hi-streak',JSON.stringify(sd));}
function getStreak(){return JSON.parse(localStorage.getItem('hi-streak')||'{"count":0}').count;}
function launchConfetti(){const canvas=document.getElementById('confettiCanvas');if(!canvas)return;canvas.style.display='block';const ctx=canvas.getContext('2d');canvas.width=window.innerWidth;canvas.height=window.innerHeight;const particles=[];const colors=['#004D40','#00897B','#4DB6AC','#66BB6A','#FFD54F','#E91E63','#4FC3F7'];for(let i=0;i<120;i++)particles.push({x:Math.random()*canvas.width,y:Math.random()*canvas.height-canvas.height,w:Math.random()*10+5,h:Math.random()*6+3,color:colors[Math.floor(Math.random()*colors.length)],vx:(Math.random()-0.5)*4,vy:Math.random()*3+2,rot:Math.random()*360,rotSpeed:(Math.random()-0.5)*10});let frame=0;function draw(){ctx.clearRect(0,0,canvas.width,canvas.height);particles.forEach(p=>{p.x+=p.vx;p.y+=p.vy;p.rot+=p.rotSpeed;ctx.save();ctx.translate(p.x,p.y);ctx.rotate(p.rot*Math.PI/180);ctx.fillStyle=p.color;ctx.fillRect(-p.w/2,-p.h/2,p.w,p.h);ctx.restore();});frame++;if(frame<120)requestAnimationFrame(draw);else{ctx.clearRect(0,0,canvas.width,canvas.height);canvas.style.display='none';}}draw();}

function renderQuiz(){const t=T[lang];const correct=[2,2,2,2,0,2,2,2,2,2];document.getElementById('quizContainer').innerHTML=QUIZ.map((q,i)=>`<div class="quiz-question scroll-reveal" id="quiz-q-${i}"><div class="quiz-q-text">${i+1}. ${q[lang]}</div><div class="quiz-options"><button class="quiz-opt" onclick="selectQuizOpt(${i},2)">${lang==='ar'?'نعم':lang==='fr'?'Oui':'Yes'}</button><button class="quiz-opt" onclick="selectQuizOpt(${i},1)">${lang==='ar'?'أحياناً':lang==='fr'?'Parfois':'Sometimes'}</button><button class="quiz-opt" onclick="selectQuizOpt(${i},0)">${lang==='ar'?'لا':lang==='fr'?'Non':'No'}</button></div></div>`).join('')+`<button class="quiz-submit" onclick="submitQuiz()">${t.submitQuiz}</button>`;document.getElementById('quizResult').classList.add('hidden');window._quizAnswers={};window._correct=correct;}
function selectQuizOpt(qi,val){window._quizAnswers[qi]=val;document.querySelectorAll(`#quiz-q-${qi} .quiz-opt`).forEach((o,oi)=>o.classList.toggle('selected',[2,1,0][oi]===val));playSound('click');}
function submitQuiz(){const ans=window._quizAnswers||{};if(Object.keys(ans).length<QUIZ.length){showToast(lang==='ar'?'أجب على جميع الأسئلة':'Answer all questions');return;}const c=window._correct;let score=0;Object.entries(ans).forEach(([qi,v])=>{if(v===c[parseInt(qi)])score++;});const pct=Math.round(score/QUIZ.length*100);let emoji,title,desc;if(pct>=80){emoji='🌟';title=lang==='ar'?'ممتاز!':'Excellent!';desc=lang==='ar'?'معرفتك بحقوق الإنسان في الإسلام رائعة!':'Your knowledge of human rights in Islam is remarkable!';}else if(pct>=50){emoji='⚖️';title=lang==='ar'?'جيد':'Good';desc=lang==='ar'?'لديك معرفة جيدة لكن هناك المزيد.':'Good knowledge but there\'s more to learn.';}else{emoji='📚';title=lang==='ar'?'تحتاج للمراجعة':'Review Needed';desc=lang==='ar'?'ابدأ بقراءة الحقوق في هذا التطبيق.':'Start reading the rights in this app.';}const r=document.getElementById('quizResult');r.classList.remove('hidden');r.innerHTML=`<div class="qr-emoji">${emoji}</div><div class="qr-score">${pct}%</div><div class="qr-title">${title}</div><div class="qr-desc">${desc}</div><button class="quiz-submit" onclick="renderQuiz()" style="margin-top:16px">${T[lang].quizAgain}</button>`;r.scrollIntoView({behavior:'smooth'});playSound('success');}

function renderAbout(){const about={ar:{disclaimerTitle:'⚠️ تنبيه مهم',disclaimer:'لست عالماً. هذا جهد متواضع لنشر فكر الشيخ الغزالي عن حقوق الإنسان.',authorName:'الشيخ محمد الغزالي',authorDates:'١٩١٧ — ١٩٩٦',authorBio:'عالم ومفكر إسلامي مصري. ألّف أكثر من ٩٤ كتاباً. درّس في جامعة الأمير عبد القادر بقسنطينة (الجزائر).',bookTitle:'عن الكتاب',bookDesc:'"حقوق الإنسان بين تعاليم الإسلام وإعلان الأمم المتحدة" — يقارن الغزالي بين حقوق الإنسان كما جاءت في الإسلام قبل ١٤٠٠ سنة وبين الإعلان العالمي لحقوق الإنسان الصادر عام ١٩٤٨. يوضح أن الإسلام سبق في كثير من هذه الحقوق وأن مصدرها إلهي ثابت.',sourcesTitle:'المصادر',sources:['كتاب "حقوق الإنسان" — الشيخ محمد الغزالي','القرآن الكريم','الإعلان العالمي لحقوق الإنسان ١٩٤٨'],contact:'تواصل: abdelhak.bourdim@gmail.com'},en:{disclaimerTitle:'⚠️ Important Notice',disclaimer:"I am not a scholar. This is a humble effort to share Sheikh al-Ghazali's thought on human rights.",authorName:'Sheikh Mohammed al-Ghazali',authorDates:'1917 — 1996',authorBio:'Egyptian Islamic scholar and thinker. Author of 94+ books. Taught at University of Emir Abdelkader in Constantine, Algeria.',bookTitle:'About the Book',bookDesc:'"Human Rights: Between Islam\'s Teachings and the UN Declaration" — Al-Ghazali compares human rights as they came in Islam 1,400 years ago with the 1948 Universal Declaration. He shows Islam preceded in many rights and that their source is divine and fixed.',sourcesTitle:'Sources',sources:['"Human Rights" — Sheikh Mohammed al-Ghazali','The Holy Quran','Universal Declaration of Human Rights 1948'],contact:'Contact: abdelhak.bourdim@gmail.com'},fr:{disclaimerTitle:'⚠️ Avis Important',disclaimer:"Je ne suis ni savant. C'est un effort humble pour partager la pensee du Sheikh al-Ghazali sur les droits de l'homme.",authorName:'Sheikh Mohammed al-Ghazali',authorDates:'1917 — 1996',authorBio:"Savant et penseur islamique egyptien. Auteur de plus de 94 livres. Professeur a l'Universite Emir Abdelkader de Constantine (Algerie).",bookTitle:'A Propos du Livre',bookDesc:'"Droits de l\'Homme entre les Enseignements de l\'Islam et la Declaration de l\'ONU" — Al-Ghazali compare les droits de l\'homme en Islam il y a 1400 ans avec la Declaration Universelle de 1948.',sourcesTitle:'Sources',sources:['"Droits de l\'Homme" — Sheikh Mohammed al-Ghazali','Le Saint Coran','Declaration Universelle des Droits de l\'Homme 1948'],contact:'Contact : abdelhak.bourdim@gmail.com'}};const a=about[lang];document.getElementById('aboutContainer').innerHTML=`<div class="about-disclaimer"><div class="about-disclaimer-title">${a.disclaimerTitle}</div><p>${a.disclaimer}</p></div><div class="about-author"><span class="about-author-icon">📚</span><div class="about-author-info"><div class="about-author-name">${a.authorName}</div><div class="about-author-dates">${a.authorDates}</div><div class="about-author-bio">${a.authorBio}</div></div></div><div class="about-section"><div class="about-section-title">${a.bookTitle}</div><p class="about-text">${a.bookDesc}</p></div><div class="about-section"><div class="about-section-title">${a.sourcesTitle}</div>${a.sources.map(s=>`<p class="about-text">&#8226; ${s}</p>`).join('')}</div><div class="about-section"><p class="about-text">${a.contact}</p></div>`;}

function renderHelp(){const h={ar:[{title:'⚠️ تنبيه',body:'لست عالماً. هذا جهد متواضع لنشر فكر الشيخ الغزالي.'},{title:'📚 المصادر',body:'كتاب "حقوق الإنسان" للشيخ محمد الغزالي.'},{title:'✨ المميزات',body:'ثلاث لغات، ٣ أنماط، ٢٠ حقاً، مقارنة، عادات، اختبار، أدعية.'}],en:[{title:'⚠️ Disclaimer',body:"I am not a scholar. This is a humble effort."},{title:'📚 Sources',body:'"Human Rights" by Sheikh Mohammed al-Ghazali.'},{title:'✨ Features',body:'Three languages, 3 themes, 20 rights, comparison, habits, quiz, duas.'}],fr:[{title:'⚠️ Avertissement',body:"Je ne suis pas un savant. C'est un effort humble."},{title:'📚 Sources',body:'"Droits de l\'Homme" par Sheikh al-Ghazali.'},{title:'✨ Fonctionnalites',body:'Trois langues, 3 themes, 20 droits, comparaison, habitudes, quiz, duas.'}]};document.getElementById('helpBody').innerHTML=h[lang].map(i=>`<div class="help-item"><div class="help-item-title">${i.title}</div><div>${i.body}</div></div>`).join('');}
function renderDuas(){document.getElementById('duaPanelContent').innerHTML=DUAS.map(d=>{const dd=d[lang];return`<div class="dua-item"><div class="dua-item-label">${dd.label}</div><div class="dua-item-ar">${dd.text}</div><div class="dua-item-tr">${dd.tr}</div></div>`;}).join('');}
function initScrollReveal(){if(!('IntersectionObserver' in window))return;const o=new IntersectionObserver(entries=>{entries.forEach(e=>{if(e.isIntersecting){e.target.classList.add('revealed');o.unobserve(e.target);}});},{threshold:0.08,rootMargin:'0px 0px -40px 0px'});function obs(){document.querySelectorAll('.scroll-reveal:not(.revealed)').forEach(el=>o.observe(el));}obs();document.querySelectorAll('.tab').forEach(t=>{t.addEventListener('click',()=>setTimeout(obs,100));});}
function initKeyboardNav(){document.addEventListener('keydown',e=>{if(e.key==='Escape'){const hp=document.getElementById('helpPanel');if(!hp.classList.contains('hidden')){toggleHelp();return;}const dp=document.getElementById('duaPanel');if(!dp.classList.contains('hidden')){toggleDuaPanel();return;}document.querySelectorAll('.principle-card.open').forEach(c=>c.classList.remove('open'));}if(e.key==='ArrowRight'||e.key==='ArrowLeft'){const panel=document.getElementById('panel-concepts');if(!panel||!panel.classList.contains('active'))return;if(document.activeElement&&document.activeElement.id==='conceptsSearch')return;e.preventDefault();const cards=Array.from(document.querySelectorAll('.principle-card')).filter(c=>c.style.display!=='none');if(!cards.length)return;if(currentConceptIdx>=0&&currentConceptIdx<cards.length)cards[currentConceptIdx].classList.remove('open');const dir=(document.documentElement.dir==='rtl')?(e.key==='ArrowRight'?-1:1):(e.key==='ArrowRight'?1:-1);currentConceptIdx=Math.max(0,Math.min(cards.length-1,currentConceptIdx+dir));cards[currentConceptIdx].classList.add('open');cards[currentConceptIdx].scrollIntoView({behavior:'smooth',block:'center'});playSound('click');}});}
function toggleCard(id){const c=document.getElementById(id);if(c){c.classList.toggle('open');playSound('click');}}
function toggleHelp(){document.getElementById('helpPanel').classList.toggle('hidden');playSound('click');}
function toggleDuaPanel(){document.getElementById('duaPanel').classList.toggle('hidden');playSound('click');}
function showToast(msg){const t=document.getElementById('toast'),m=document.getElementById('toastMsg');if(t&&m){m.textContent=msg;t.style.display='block';setTimeout(()=>t.style.display='none',2500);}}
function initScrollTop(){const btn=document.getElementById('scrollTop');window.addEventListener('scroll',()=>{if(btn)btn.classList.toggle('visible',window.scrollY>300);});}
const AudioCtx=window.AudioContext||window.webkitAudioContext;let audioCtx;
function playSound(type){try{if(!audioCtx)audioCtx=new AudioCtx();const osc=audioCtx.createOscillator(),gain=audioCtx.createGain();osc.connect(gain);gain.connect(audioCtx.destination);gain.gain.value=0.06;if(type==='click'){osc.frequency.value=800;osc.type='sine';gain.gain.value=0.04;}else if(type==='success'){osc.frequency.value=523;osc.type='sine';}else if(type==='theme'){osc.frequency.value=440;osc.type='triangle';gain.gain.value=0.05;}osc.start();osc.stop(audioCtx.currentTime+0.1);}catch(e){}}
